import { css, cva, type RecipeVariant } from "styled-system/css";

/** Visually hides text while keeping it exposed to assistive technologies. */
export const visuallyHidden = css({
  border: "0",
  clip: "rect(0, 0, 0, 0)",
  h: "1px",
  m: "-1px",
  overflow: "hidden",
  p: "0",
  position: "absolute",
  whiteSpace: "nowrap",
  w: "1px",
});

