/** Variant values inferred from the shared button recipe. */
type ButtonRecipeVariant = RecipeVariant<typeof buttonRecipe>;

/** Visual treatment available for the shared button. */
export type ButtonVariant = ButtonRecipeVariant["variant"];

/** Color role available for the shared button. */
export type ButtonColor = ButtonRecipeVariant["color"];

/** Size available for the shared button. */
export type ButtonSize = ButtonRecipeVariant["size"];

/** Right-icon motion available for buttons with directional CTAs. */
export type ButtonIconMotion = "slide-right";
